#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    string s;
    long long ans=0;
    cin>>n;
    for(int i=0;i<n;i++){
        getline(cin,s);
        if(i==0)getline(cin,s);
        for(int j=0;j<s.size()-2;j++){
            if(s[j]!=' '){
                if(s[j]=='#' && s[j+1]==' '){
                	bool flag=false;
                	for(int z=j+2;z<s.size();z++)
						if(s[z]!=' '){
                			flag=true;
                			break;
						}
                    if(flag){
                    	ans++;
                    	//cout<<s<<endl;
					}
                }
				break;
            }
        }
    }
    cout<<ans;
    return 0;
}
